/** Allergen flag key type. */
type AllergenFlagKey = keyof AllergenFlags;

/** Map from canonical allergen name to CuratedMeal.allergen_flags key. */
const ALLERGEN_FLAG_MAP: Record<string, AllergenFlagKey> = {
  dairy: "contains_dairy",
  eggs: "contains_eggs",
  fish: "contains_fish",
  shellfish: "contains_shellfish",
  nuts: "contains_nuts",
  peanuts: "contains_peanuts",
  wheat: "contains_wheat",
  soy: "contains_soy",
  sesame: "contains_sesame",
};

/**
 * Find recipes matching a user's profile.
 *
 * @param diet - the user's DietType (from the engine)
 * @param phase - the user's NutritionPhase (cut/bulk/recomp/maintain/reverse_diet)
 * @param mealType - which meal slot to fill
 * @param allergenAvoid - set of allergens to exclude (from the onboarding allergies field)
 * @returns array of matching CuratedMeal IDs, sorted by macro-fit (closest to target)
 */
export function findRecipesForProfile(
  diet: DietType,
  phase: NutritionPhase,
  mealType: "breakfast" | "lunch" | "dinner" | "snack",
  allergenAvoid: Set<string> = new Set(),
): string[] {
  const profileId = `${diet}__${phase}__${mealType}`;
  const profile = MEAL_PROFILES.find((p) => p.id === profileId);
  if (!profile) return [];

  // ESM import at top of file — no circular dep because mealDatabase.ts
  // does not import from mealProfiles.ts.
  return MEAL_DATABASE.filter((meal) => {
    // Diet check
    if (!meal.diet_compatibility.includes(diet)) return false;

    // Allergen check
    for (const allergen of allergenAvoid) {
      const flag = ALLERGEN_FLAG_MAP[allergen];
      if (flag && meal.allergen_flags[flag]) return false;
    }

    // Meal type check (allow lunch/dinner interchange)
    if (mealType === "lunch" || mealType === "dinner") {
      if (!meal.meal_types.some((m) => m === "lunch" || m === "dinner")) return false;
    } else {
      if (!meal.meal_types.includes(mealType)) return false;
    }

    // Calorie range (±30%)
    const [calLo, calHi] = profile.calorie_range;
    if (meal.calories < calLo || meal.calories > calHi) return false;

    // Protein minimum (±25%)
    if (meal.protein_g < profile.protein_range[0]) return false;

    return true;
  })
    .sort((a, b) => {
      // Sort by closest calorie match to target
      const aDiff = Math.abs(a.calories - profile.target_calories);
      const bDiff = Math.abs(b.calories - profile.target_calories);
      return aDiff - bDiff;
    })
    .map((m) => m.id);
}
